package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testIsCommentMarkerSet_WhenCommentMarkerIsNull() {
        CSVFormat csvFormat = CSVFormat.DEFAULT.withCommentMarker((Character) null);
        assertFalse(csvFormat.isCommentMarkerSet());
    }

    @Test
    void testIsCommentMarkerSet_WhenCommentMarkerIsSet() {
        CSVFormat csvFormat = CSVFormat.DEFAULT.withCommentMarker('#');
        assertTrue(csvFormat.isCommentMarkerSet());
    }

    @Test
    void testIsCommentMarkerSet_WithWithCommentMarkerMethod() {
        CSVFormat csvFormat = CSVFormat.DEFAULT.withCommentMarker('#');
        assertTrue(csvFormat.isCommentMarkerSet());

        CSVFormat csvFormatNull = CSVFormat.DEFAULT.withCommentMarker((Character) null);
        assertFalse(csvFormatNull.isCommentMarkerSet());
    }
}
